class Solution:
    def makeStringSorted(self, s):
        MOD = 10**9 + 7
        n = len(s)
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (n + 1)
        inv_fact[n] = pow(fact[n], MOD - 2, MOD)
        for i in range(n - 1, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - 97] += 1
        ans = 0
        for i in range(n):
            c = ord(s[i]) - 97
            # sum of counts of letters smaller than current
            for smaller in range(c):
                if cnt[smaller] == 0:
                    continue
                cnt[smaller] -= 1
                rem = n - i - 1
                ways = fact[rem]
                for k in range(26):
                    ways = ways * inv_fact[cnt[k]] % MOD
                ans = (ans + ways) % MOD
                cnt[smaller] += 1
            cnt[c] -= 1
        return ans % MOD

