var makeStringSorted = function(s) {
    const MOD = 1000000007n;
    const n = s.length;
    const fact = new Array(n + 1).fill(1n);
    for (let i = 1; i <= n; i++) fact[i] = fact[i - 1] * BigInt(i) % MOD;
    const power = (b, e) => {
        let r = 1n; b %= MOD;
        while (e > 0n) {
            if (e & 1n) r = r * b % MOD;
            b = b * b % MOD;
            e >>= 1n;
        }
        return r;
    };
    const invFact = new Array(n + 1).fill(1n);
    invFact[n] = power(fact[n], MOD - 2n);
    for (let i = n - 1; i >= 0; i--) invFact[i] = invFact[i + 1] * BigInt(i + 1) % MOD;
    const cnt = new Array(26).fill(0);
    for (const ch of s) cnt[ch.charCodeAt(0) - 97]++;
    let ans = 0n;
    for (let i = 0; i < n; i++) {
        const c = s.charCodeAt(i) - 97;
        for (let smaller = 0; smaller < c; smaller++) {
            if (cnt[smaller] === 0) continue;
            cnt[smaller]--;
            const rem = n - i - 1;
            let ways = fact[rem];
            for (let k = 0; k < 26; k++) ways = ways * invFact[cnt[k]] % MOD;
            ans = (ans + ways) % MOD;
            cnt[smaller]++;
        }
        cnt[c]--;
    }
    return Number(ans % MOD);
};
